import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctors() {
  const navigate = useNavigate();

  // 🔍 Search state
  const [search, setSearch] = useState("");

  // 👨‍⚕️ Doctor data
  const doctors = [
    { name: "Dr. John Smith", specialty: "Cardiologist" },
    { name: "Dr. Sarah Lee", specialty: "Dermatologist" },
    { name: "Dr. David Kumar", specialty: "Orthopedic" },
    { name: "Dr. Priya Nair", specialty: "Pediatrician" },
  ];

  const handleViewProfile = (name, specialty) => {
    navigate("/doctorprofile", {
      state: { name, specialty }
    });
  };

  // 🔍 FILTER LOGIC
  const filteredDoctors = doctors.filter((doc) =>
    doc.name.toLowerCase().includes(search.toLowerCase()) ||
    doc.specialty.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div style={styles.container}>

      <Navbar />

      {/* SEARCH */}
      <div style={styles.searchContainer}>
        <input
          type="text"
          placeholder="Search doctor name or profession..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={styles.searchInput}
        />
      </div>

      {/* CARDS */}
      <div style={styles.cardContainer}>

        {filteredDoctors.length > 0 ? (
          filteredDoctors.map((doc, index) => (
            <div key={index} style={styles.card}>
              <img
                src="https://cdn-icons-png.flaticon.com/512/387/387561.png"
                style={styles.image}
              />

              <h3>{doc.name}</h3>
              <p>{doc.specialty}</p>

              <button
                style={styles.button}
                onClick={() => handleViewProfile(doc.name, doc.specialty)}
              >
                View Profile
              </button>
            </div>
          ))
        ) : (
          <p style={{ textAlign: "center", width: "100%" }}>
            No doctors found 😔
          </p>
        )}

      </div>

      <Footer />

    </div>
  );
}

export default Doctors;


const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    minHeight: "100vh",
    display: "flex",
    flexDirection: "column",
    backgroundColor: "#f4f6f9",
  },

  searchContainer: {
    textAlign: "center",
    margin: "20px 0",
  },

  searchInput: {
    width: "320px",
    padding: "10px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  cardContainer: {
    flex: 1,
    display: "flex",
    flexWrap: "wrap",
    justifyContent: "center",
    gap: "20px",
    padding: "20px",
  },

  card: {
    backgroundColor: "white",
    width: "220px",
    padding: "20px",
    borderRadius: "10px",
    textAlign: "center",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },

  image: {
    width: "90px",
    height: "90px",
    borderRadius: "50%",
    marginBottom: "10px",
  },

  button: {
    marginTop: "10px",
    padding: "8px 15px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },
};
